#include <bits/stdc++.h>
using namespace std;

bool isOddCycle(int u, vector <int>& level, vector <vector <int>>& adj, int l){
    level[u] = l;
    for(int v: adj[u]){
        if(level[v] == -1){
            if(isOddCycle(v, level, adj, l + 1)) return true;
        }else if((l - level[v]) % 2 == 0) return true;
    }
    return false;
}

void solve(){
    int n, m;
    cin >> n >> m;

    vector <vector <int> > adj(1+n);
    while(m--){
        int u, v;
        cin >> u >> v;

        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    vector <int> level(1+n, -1);
    for(int u = 1; u <= n; u++){
        if(level[u] == -1){
            if(isOddCycle(u, level, adj, 0)){
                cout << "NO\n";
                return;
            }
        }
    }
    cout << "YES\n";
}

int main(){
    int t = 1;
    cin >> t;

    while(t--) solve();
}

