import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    static boolean isOddCycle(int u, int[] level, List < List < Integer >> adj, int l) {
        level[u] = l;
        for (int v: adj.get(u)) {
            if (level[v] == -1) {
                if (isOddCycle(v, level, adj, l + 1)) return true;
            } else if ((l - level[v]) % 2 == 0) return true;
        }
        return false;
    }

    static void solve(Scanner scanner) {
        int n = scanner.nextInt();
        int m = scanner.nextInt();

        List < List < Integer >> adj = new ArrayList < > (n + 1);
        for (int i = 0; i <= n; i++) {
            adj.add(new ArrayList < > ());
        }

        for (int i = 0; i < m; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            adj.get(u).add(v);
            adj.get(v).add(u);
        }

        int[] level = new int[n + 1];
        Arrays.fill(level, -1);

        for (int u = 1; u <= n; u++) {
            if (level[u] == -1) {
                if (isOddCycle(u, level, adj, 0)) {
                    System.out.println("NO");
                    return;
                }
            }
        }
        System.out.println("YES");
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t--> 0) {
            solve(scanner);
        }
        scanner.close();
    }
}
